import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import products from "../data/ProductData";
import "../index.css";

const Checkout = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [promoCode, setPromoCode] = useState("");
  const [discount, setDiscount] = useState(0);
  const [orderPlaced, setOrderPlaced] = useState(false);

  useEffect(() => {
    if (!id) return;
    const dummy = products.find((p) => String(p.id) === id);
    if (dummy) {
      setProduct(dummy);
      return;
    }
    axios
      .get('http://localhost:5000/api/products/${id}')
      .then((res) => setProduct(res.data))
      .catch(() =>
        setProduct({ name: "Unknown Product", price: 0, _id: id })
      );
  }, [id]);

  const handleApplyPromo = () => {
    if (promoCode.trim().toLowerCase() === "save10") {
      setDiscount(0.1); // 10% off
      alert("Promo code applied! 10% discount added.");
    } else {
      setDiscount(0);
      alert("Invalid promo code");
    }
  };

  const handlePlaceOrder = () => {
    setOrderPlaced(true);
    setTimeout(() => navigate("/orders"), 2000);
  };

  if (!product) return <p>Loading...</p>;
  if (orderPlaced) return <h2 className="success-msg">✅ Order placed successfully!</h2>;

  const tax = Math.round(product.price * 0.02);
  const discountedPrice = Math.round(product.price * (1 - discount));
  const total = discountedPrice + tax;

  return (
    <div className="checkout-summary-container">
      <h2 className="summary-title">Order Summary</h2>
      <div className="divider"></div>

      <div className="summary-section">
        <h4>SELECT ADDRESS</h4>
        <div className="address-box">
          Soumyaranjan, Burnt Indian Cloud Kitchen, Kanan Bihar Phase 2, Khorda, Odisha
        </div>
      </div>

      <div className="summary-section">
        <h4>PROMO CODE</h4>
        <div className="promo-row">
          <input
            type="text"
            placeholder="Enter promo code"
            value={promoCode}
            onChange={(e) => setPromoCode(e.target.value)}
          />
          <button className="apply-btn" onClick={handleApplyPromo}>Apply</button>
        </div>
      </div>

      <div className="divider"></div>

      <div className="summary-totals">
        <div className="row">
          <span>Price</span>
          <span>₹{product.price}</span>
        </div>
        <div className="row">
          <span>Shipping Fee</span>
          <span>Free</span>
        </div>
        <div className="row">
          <span>Tax (2%)</span>
          <span>₹{tax}</span>
        </div>
        {discount > 0 && (
          <div className="row discount">
            <span>Discount (10%)</span>
            <span>-₹{Math.round(product.price * 0.1)}</span>
          </div>
        )}
        <div className="divider"></div>
        <div className="row total">
          <strong>Total</strong>
          <strong>₹{total}</strong>
        </div>
      </div>

      <button className="place-order-btn" onClick={handlePlaceOrder}>
        Place Order
      </button>
    </div>
  );
};

export default Checkout;
